import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import VirtualKeyboard from '../components/VirtualKeyboard';
import './Lesson.css';

// Split full content into lines
const splitIntoLines = (text, lessonType) => {
  if (lessonType === 'paragraph') return [text];

  if (lessonType === 'sentences') {
    // Split keeping the punctuation, preserve spaces between words
    const sentences = text
      .split(/(?<=[.!?])\s+/)   // split AFTER punctuation + whitespace
      .map(s => s.trim())
      .filter(Boolean);
    return sentences.length > 0 ? sentences : [text];
  }

  // intro / random-words / meaningful-words → 10-word chunks
  const words = text.trim().split(/\s+/);
  const chunks = [];
  const PER_LINE = 10;
  for (let i = 0; i < words.length; i += PER_LINE) {
    chunks.push(words.slice(i, i + PER_LINE).join(' '));
  }
  return chunks;
};

const Lesson = () => {
  const { chapterId, lessonId } = useParams();
  const navigate = useNavigate();

  const [lessonData, setLessonData]   = useState(null);
  const [loading, setLoading]         = useState(true);
  const [error, setError]             = useState(null);

  // Line-by-line state
  const [lines, setLines]             = useState([]);
  const [lineIndex, setLineIndex]     = useState(0);
  const [charIndex, setCharIndex]     = useState(0);
  const [wrongChar, setWrongChar]     = useState(false);
  const [linePhase, setLinePhase]     = useState('visible'); // 'visible' | 'fadeout' | 'fadein'

  // Global stats
  const [totalChars, setTotalChars]   = useState(0);
  const [errors, setErrors]           = useState(0);
  const [userInput, setUserInput]     = useState('');

  // Timer
  const [timeElapsed, setTimeElapsed] = useState(0);

  // Completion
  const [isComplete, setIsComplete]   = useState(false);
  const [showResults, setShowResults] = useState(false);

  // Sound feedback
  const [lastKeyCorrect, setLastKeyCorrect] = useState(null);

  const inputRef   = useRef(null);
  const timerRef   = useRef(null);
  const startRef   = useRef(null); // stable start time ref
  const errorsRef  = useRef(0);    // stable errors ref for submit
  const charsRef   = useRef(0);    // stable chars ref for submit

  // ─── Load lesson ────────────────────────────────────────
  useEffect(() => {
    fetchLesson();
    return () => clearInterval(timerRef.current);
  }, [chapterId, lessonId]);

  const fetchLesson = async () => {
    try {
      const res = await chaptersAPI.getLesson(chapterId, lessonId);
      const data = res.data;
      setLessonData(data);
      const ls = splitIntoLines(data.lesson.content, data.lesson.lessonType);
      setLines(ls);
    } catch {
      setError('Failed to load lesson');
    } finally {
      setLoading(false);
    }
  };

  // Keep input focused after line change
  useEffect(() => {
    if (!isComplete && inputRef.current) inputRef.current.focus();
  }, [isComplete, lineIndex]);

  // ─── Timer ───────────────────────────────────────────────
  const startTimer = () => {
    if (startRef.current) return;
    startRef.current = Date.now();
    timerRef.current = setInterval(() => {
      setTimeElapsed(Math.floor((Date.now() - startRef.current) / 1000));
    }, 500);
  };

  // ─── Live WPM ────────────────────────────────────────────
  const calcWpm = () => {
    if (!startRef.current || charsRef.current === 0) return 0;
    const mins = (Date.now() - startRef.current) / 60000;
    if (mins < 0.01) return 0;
    return Math.round((charsRef.current / 5) / mins);
  };

  // ─── Submit ───────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    clearInterval(timerRef.current);
    const elapsed = startRef.current ? Math.round((Date.now() - startRef.current) / 1000) : 0;
    setTimeElapsed(elapsed);

    const mins = elapsed / 60 || 0.1;
    const wpm = Math.round((charsRef.current / 5) / mins);
    const totalLen = lines.join(' ').length || 1;
    const accuracy = Math.max(0, Math.round(((totalLen - errorsRef.current) / totalLen) * 100));

    try {
      await progressAPI.submitLesson({ chapterId, lessonId, wpm, accuracy });
    } catch (e) {
      console.error('Submit failed', e);
    }
    setIsComplete(true);
    setShowResults(true);
  }, [chapterId, lessonId, lines]);

  // ─── Line transition ──────────────────────────────────────
  const advanceToNextLine = useCallback(() => {
    setLinePhase('fadeout');
    setTimeout(() => {
      const next = lineIndex + 1;
      if (next >= lines.length) {
        handleSubmit();
        return;
      }
      setLineIndex(next);
      setCharIndex(0);
      setUserInput('');
      setWrongChar(false);
      setLinePhase('fadein');
      setTimeout(() => setLinePhase('visible'), 250);
    }, 280);
  }, [lineIndex, lines.length, handleSubmit]);

  // ─── Typing handler ───────────────────────────────────────
  const handleInputChange = (e) => {
    if (linePhase !== 'visible' || isComplete) return;

    const value = e.target.value;
    const currentLine = lines[lineIndex] || '';
    const isDeleting = value.length < userInput.length;

    if (!startRef.current) startTimer();

    if (isDeleting) {
      setUserInput(value);
      setCharIndex(prev => Math.max(0, prev - 1));
      setWrongChar(false);
      setLastKeyCorrect(null);
      return;
    }

    const typedChar  = value[value.length - 1];
    const expectedChar = currentLine[charIndex];

    if (typedChar !== expectedChar) {
      errorsRef.current += 1;
      setErrors(errorsRef.current);
      setWrongChar(true);
      setLastKeyCorrect(false);
      return; // don't advance, don't store bad input
    }

    // Correct keystroke
    setWrongChar(false);
    setLastKeyCorrect(true);
    setUserInput(value);

    charsRef.current += 1;
    setTotalChars(charsRef.current);

    const newCharIndex = charIndex + 1;
    setCharIndex(newCharIndex);

    if (newCharIndex >= currentLine.length) {
      advanceToNextLine();
    }
  };

  // ─── Render current line chars ────────────────────────────
  const renderLine = () => {
    const line = lines[lineIndex] || '';
    const chars = line.split('').map((char, i) => {
      let cls = '';
      if (i < charIndex)        cls = 'correct';
      else if (i === charIndex) cls = wrongChar ? 'incorrect' : 'current';
      return <span key={i} className={cls}>{char}</span>;
    });

    // Slide the text left so the current char stays visible
    // Each char ≈ 1.3rem wide at 2.2rem font (monospace)
    const slideLeft = charIndex > 0 ? `calc(-${charIndex} * 1.35rem)` : '0px';

    return (
      <span
        className="typing-line-inner"
        style={{ transform: `translateX(${slideLeft})`, transition: 'transform 0.1s linear' }}
      >
        {chars}
      </span>
    );
  };

  const getCurrentKey = () => {
    if (isComplete || !lines[lineIndex]) return null;
    return lines[lineIndex][charIndex] || null;
  };

  // ─── Loading / Error ──────────────────────────────────────
  if (loading) return <div className="loading">Loading lesson...</div>;
  if (error || !lessonData) return (
    <div className="container">
      <div className="error">{error || 'Lesson not found'}</div>
      <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
    </div>
  );

  const { chapter, lesson } = lessonData;
  const showKeyboard = lesson.lessonType !== 'paragraph';
  const liveAccuracy = totalChars > 0 ? Math.round(((totalChars - errors) / totalChars) * 100) : 100;
  const progressPct  = lines.length > 0 ? Math.round((lineIndex / lines.length) * 100) : 0;

  // Final result stats
  const resultElapsed = timeElapsed;
  const resultWpm = (() => {
    const mins = resultElapsed / 60 || 0.1;
    return Math.round((charsRef.current / 5) / mins);
  })();
  const resultAccuracy = lines.length > 0
    ? Math.max(0, Math.round(((lines.join(' ').length - errorsRef.current) / lines.join(' ').length) * 100))
    : 100;

  return (
    <div className="lesson-container-with-panel">
      <div className="lesson-main-area">

        {/* ── Header ── */}
        <div className="lesson-header-compact">
          <h3>Chapter {chapter.chapterNumber} • Lesson {lesson.lessonNumber}</h3>
          <span className="header-divider">|</span>
          <p>{lesson.lessonTitle}</p>
        </div>

        {/* ── Progress Bar ── */}
        <div className="line-progress-bar">
          <div className="line-progress-fill" style={{ width: `${progressPct}%` }} />
          <span className="line-counter-inline">Line {lineIndex + 1}/{lines.length}</span>
        </div>

        {/* ── Target Text (one line at a time) ── */}
        <div className={`typing-content line-${linePhase}`}>
          {renderLine()}
        </div>

        {/* ── Typing Input ── */}
        {!isComplete && (
          <input
            ref={inputRef}
            type="text"
            className="typing-input"
            value={userInput}
            onChange={handleInputChange}
            placeholder="Start typing..."
            autoComplete="off"
            autoCorrect="off"
            autoCapitalize="off"
            spellCheck="false"
            autoFocus
          />
        )}

        {/* ── Virtual Keyboard ── */}
        {showKeyboard && !isComplete && (
          <VirtualKeyboard activeKey={getCurrentKey()} isCorrect={lastKeyCorrect} />
        )}
      </div>

      {/* ── Right Control Panel ── */}
      {!isComplete && (
        <div className="control-panel-right">
          <div className="control-stat">
            <div className="stat-label">⏱️ TIMER</div>
            <div className="stat-value-large timer-color">{timeElapsed}s</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">✓ ACCURACY</div>
            <div className="stat-value-large accuracy-color">{liveAccuracy}%</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">❌ ERRORS</div>
            <div className="stat-value-large error-color">{errors}</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">⚡ WPM</div>
            <div className="stat-value-large wpm-color">{calcWpm()}</div>
          </div>
          <div className="control-buttons">
            <button className="btn-control btn-submit" onClick={handleSubmit}>Submit</button>
            <button className="btn-control btn-exit" onClick={() => navigate('/learn')}>Exit</button>
          </div>
        </div>
      )}

      {/* ── Results Modal ── */}
      {showResults && (
        <div className="results-modal">
          <div className="results-content">
            <h2>Lesson Complete! 🎉</h2>
            <div className="results-stats">
              <div className="result-stat"><h3>{resultWpm}</h3><p>Words Per Minute</p></div>
              <div className="result-stat"><h3>{resultAccuracy}%</h3><p>Accuracy</p></div>
              <div className="result-stat"><h3>{resultElapsed}s</h3><p>Time Taken</p></div>
              <div className="result-stat"><h3>{errorsRef.current}</h3><p>Errors</p></div>
            </div>
            <div className="results-actions">
              <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
              <button className="btn btn-secondary" onClick={() => window.location.reload()}>Try Again</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Lesson;
